SET NAMES utf8mb4;

CREATE TABLE `production_plan_schedules`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `file_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ファイル名',
  `processed_at` datetime NOT NULL COMMENT '処理日時',
  `machine_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '設備名',
  `product_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '生産品種',
  `production_order` int NULL DEFAULT NULL COMMENT '生産順序',
  `planned_quantity` int NULL DEFAULT NULL COMMENT '生産計画数',
  `production_start_date` date NULL DEFAULT NULL COMMENT '生産開始日',
  `production_end_date` date NULL DEFAULT NULL COMMENT '生産終了日',
  `actual_production` int NULL DEFAULT NULL COMMENT '生産実績',
  `variance` int NULL DEFAULT NULL COMMENT '差異',
  `achievement_rate` decimal(5, 2) NULL DEFAULT NULL COMMENT '達成率(%)',
  `total_production_time` decimal(10, 2) NULL DEFAULT NULL COMMENT '総生産時間(時間)',
  `operation_variance` decimal(10, 2) NULL DEFAULT NULL COMMENT '操業度差異',
  `material_lot_count` int NULL DEFAULT NULL COMMENT '材料ロット数',
  `material_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '材料名',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_file_name`(`file_name` ASC) USING BTREE,
  INDEX `idx_processed_at`(`processed_at` ASC) USING BTREE,
  INDEX `idx_equipment_name`(`machine_name` ASC) USING BTREE,
  INDEX `idx_production_dates`(`production_start_date` ASC, `production_end_date` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 231938 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '生産状況データテーブル' ROW_FORMAT = Dynamic;
